export class Item extends BaseItem {

  constructor(data, url, path) {
    super(data, url);
    this._path = path;
    this._incomplete = false;
    this._privateKeys.push('_path', '_incomplete');
  }

  getBrowserPath() {
    return this._path;
  }

}
